return [{ json: {
  report_title: 'Q3 2026 Onboarding & Adoption Research Synthesis',
  period: 'Q3 2026',
  studies: [
    { study: 'Usability Test — Onboarding v2.3 (July 2026)', type: 'usability', participants: 5, key_findings: ['Task completion rate: 40% for recurring tasks, 60% for project creation, 80% for task assignment', 'Systemic issue: feature discoverability — users look in wrong places for key actions', 'Recurring task option is critically hard to find — 3/5 participants failed', 'Inline editing model is unexpected — users anticipate modal dialogs'] },
    { study: 'NPS Survey Q2 2026 (n=150)', type: 'survey', participants: 150, key_findings: ['NPS: 40. Promoters driven primarily by recurring tasks value', 'Top detractor drivers: onboarding confusion, team adoption friction, search failure', 'Feature requests by frequency: Teams integration (12%), Gantt view (9%), bulk edit (7%), notification controls (6%)'] },
    { study: 'Customer Interviews — Switching Study (n=12)', type: 'interviews', participants: 12, key_findings: ['Primary switching trigger: recurring tasks accessibility vs Asana', 'Retention risk: team adoption stalls when non-PM teammates do not see value in week 1', 'Enterprise PMs blocked by missing RBAC and Teams integration at renewal'] },
    { study: 'Feature Usage Analytics', type: 'analytics', participants: null, key_findings: ['Recurring tasks used by 28% of accounts — 2x NPS, 3x retention for those accounts', 'Task dependencies used by 12% — exclusively Segment C (enterprise)', 'Segment A (1-5 users) median LTV: 4 months. Key churn window: months 2-4'] }
  ],
  audience: 'Product, Design, and Engineering leadership',
  executive_summary_requested: true
} }];

const d = $input.first().json;
const studyText = d.studies.map(s => `  Study: ${s.study} (${s.type}${s.participants ? ', n='+s.participants : ''})
  Findings:
${s.key_findings.map(f=>'    - '+f).join('
')}`).join('

');
const system = `You are a senior UX researcher synthesising findings from multiple research studies into a structured report. You identify patterns that appear across studies, reconcile conflicting findings, prioritise recommendations by impact, and write clearly for product and engineering leadership. Return ONLY valid JSON.`;
const user = `Build a research synthesis report for: ${d.report_title}
Period: ${d.period}
Audience: ${d.audience}

Studies:
${studyText}

Return JSON:
{
  "executive_summary": "string — 4-5 sentences covering the most important finding and its strategic implication",
  "cross_study_patterns": [{ "pattern": "string", "confidence": "high|medium|low", "supporting_studies": ["string"], "strategic_implication": "string" }],
  "reconciled_findings": [{ "topic": "string", "what_different_studies_say": "string", "synthesis": "string" }],
  "prioritised_recommendations": [{ "recommendation": "string", "priority": "high|medium|low", "effort": "high|medium|low", "evidence_strength": "strong|moderate|weak", "rationale": "string" }],
  "open_questions": ["string — what we still do not know that matters"],
  "next_studies_suggested": [{ "study": "string", "why": "string" }]
}`;
return [{ json: { data: d, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Synthesis Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.cross_study_patterns || !Array.isArray(parsed.cross_study_patterns)) return [{ json: { _error: true, reason: 'Missing cross_study_patterns' } }];
return [{ json: { _error: false, report: parsed, meta: { title: upstream.data.report_title, period: upstream.data.period, study_count: upstream.data.studies.length, generated_at: new Date().toISOString() } } }];
